//! Spec-compliance tests: Paragraph & Run Formatting (ISO 29500-1 §17.2, §17.3)
//!
//! These tests verify our implementation against specific OOXML paragraph and
//! run formatting constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use std::fs;

use stemma::{
    DocxRuntime, ExportMode, InlineNode, Mark, MarkValue, SimpleRuntime, TransactionMeta,
};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/formatting";

// ── w:spacing (paragraph spacing) ───────────────────────────────────────

/// ISO 29500-1 §17.3.1.33: w:spacing controls before/after/line spacing.
///
/// POSITIVE: The parser correctly exposes spacing values on ParagraphNode.
/// (The audit doc marked this as P0 gap, but it's actually implemented.)
#[test]
fn spec_paragraph_spacing_is_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "paragraph-spacing");

    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 3,
        "should have at least 3 paragraphs, got {}",
        paras.len()
    );

    // First paragraph: before=480 (24pt), after=0
    let p1 = &paras[0];
    let spacing1 = p1.spacing.as_ref().expect(
        "paragraph 1 should have spacing parsed. \
         w:spacing with before=480 is present in the XML but not exposed in the domain model.",
    );
    assert_eq!(
        spacing1.before,
        Some(480),
        "paragraph 1 spacing.before should be 480 twips (24pt)"
    );

    // Second paragraph: before=0, after=240 (12pt), line=360 (1.5), lineRule=auto
    let p2 = &paras[1];
    let spacing2 = p2
        .spacing
        .as_ref()
        .expect("paragraph 2 should have spacing");
    assert_eq!(
        spacing2.after,
        Some(240),
        "paragraph 2 spacing.after should be 240 twips (12pt)"
    );
    assert_eq!(
        spacing2.line,
        Some(360),
        "paragraph 2 spacing.line should be 360 (1.5 lines)"
    );

    // Third paragraph: line=360, lineRule=exact
    let p3 = &paras[2];
    let spacing3 = p3
        .spacing
        .as_ref()
        .expect("paragraph 3 should have spacing");
    assert_eq!(
        spacing3.line,
        Some(360),
        "paragraph 3 spacing.line should be 360 twips (18pt)"
    );
}

// ── w:pBdr (paragraph borders) ──────────────────────────────────────────

/// ISO 29500-1 §17.3.1.24: pBdr defines borders around a paragraph.
///
/// POSITIVE: The parser correctly exposes paragraph borders.
/// (The audit doc marked this as P0 gap, but it's actually implemented.)
#[test]
fn spec_paragraph_borders_is_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "paragraph-borders");

    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "should have at least 2 paragraphs, got {}",
        paras.len()
    );

    // First paragraph: has bottom border
    let p1 = &paras[0];
    let borders1 = p1.borders.as_ref().expect(
        "paragraph 1 should have borders parsed. \
         w:pBdr with w:bottom is present but not exposed in the domain model.",
    );
    assert!(
        borders1.bottom.is_some(),
        "paragraph 1 should have a bottom border (signature line style)"
    );

    // Second paragraph: has box border (all sides)
    let p2 = &paras[1];
    let borders2 = p2
        .borders
        .as_ref()
        .expect("paragraph 2 should have borders");
    assert!(borders2.top.is_some(), "paragraph 2 should have top border");
    assert!(
        borders2.left.is_some(),
        "paragraph 2 should have left border"
    );
    assert!(
        borders2.bottom.is_some(),
        "paragraph 2 should have bottom border"
    );
    assert!(
        borders2.right.is_some(),
        "paragraph 2 should have right border"
    );
}

// ── w:vanish (hidden text) ──────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.41: w:vanish makes text hidden.
///
/// POSITIVE: Text with w:vanish now carries Mark::Vanish.
#[test]
fn spec_vanish_is_handled() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "vanish");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let p = &paras[0];
    let inlines = p.all_inlines_owned();
    let text_nodes: Vec<&stemma::TextNode> = inlines
        .iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect();

    let hidden_run = text_nodes
        .iter()
        .find(|t| t.text.contains("hidden"))
        .expect("should have a text run containing 'hidden'");

    assert!(
        hidden_run.style_props.vanish == MarkValue::On,
        "Hidden text (w:vanish) should have vanish=On. \
         Run '{}' has vanish: {:?}",
        hidden_run.text,
        hidden_run.style_props.vanish
    );
}

