// ── Toggle property override semantics ──────────────────────────────────

/// MS-OI29500 §2.1.258: Word uses RESET (override) semantics between
/// paragraph style and character style levels, not XOR.
///
/// Setup: paragraph style sets bold=true, character style also sets bold=true.
/// Word behavior: bold=true (char style overrides para style).
#[test]
fn spec_toggle_xor_bold() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-xor");

    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "should have at least 2 paragraphs, got {}",
        paras.len()
    );

    // First paragraph: BoldPara style (bold=true) + BoldChar char style (bold=true)
    // MS-OI29500 §2.1.258: char style overrides (resets) para style → bold=true
    let p1 = &paras[0];
    let inlines1 = p1.all_inlines_owned();
    let text_nodes1: Vec<&stemma::TextNode> = inlines1
        .iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect();

    assert!(!text_nodes1.is_empty(), "first paragraph should have text");
    let is_bold = text_nodes1[0].marks.contains(&Mark::Bold);

    assert!(
        is_bold,
        "With override semantics (MS-OI29500 §2.1.258), paragraph style bold=true + \
         character style bold=true should result in bold=true. \
         Character style overrides (resets) paragraph style."
    );

    // Second paragraph: BoldPara style (bold=true), no character style
    // Should be bold=true
    let p2 = &paras[1];
    let inlines2 = p2.all_inlines_owned();
    let text_nodes2: Vec<&stemma::TextNode> = inlines2
        .iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect();

    assert!(!text_nodes2.is_empty(), "second paragraph should have text");
    let is_bold2 = text_nodes2[0].marks.contains(&Mark::Bold);
    assert!(
        is_bold2,
        "Second paragraph with only paragraph style bold=true should be bold"
    );
}

// ── sectPr in pPr ───────────────────────────────────────────────────────

/// ISO 29500-1 §17.6.18: sectPr in pPr marks a section break.
///
/// The typed section_properties field should be populated.
#[test]
fn spec_sect_pr_in_ppr_is_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "sect-pr-in-ppr");

    let paras = common::all_paragraphs(&doc);

    let has_sect_pr = paras.iter().any(|p| p.section_properties.is_some());

    assert!(
        has_sect_pr,
        "At least one paragraph should have section_properties from sectPr in pPr. \
         The fixture has a section break between two paragraphs. \
         Paragraphs found: {}",
        paras.len()
    );
}

/// sectPr in pPr should survive a diff/redline roundtrip.
#[test]
fn spec_sect_pr_in_ppr_survives_redline() {
    let path = format!("{FIXTURES}/sect-pr-in-ppr/input.docx");
    let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));

    let runtime = SimpleRuntime::new();
    let import = runtime.import_docx(&bytes).expect("import");

    // Diff against itself (identity) and apply redline
    let import2 = runtime.import_docx(&bytes).expect("import2");
    let meta = TransactionMeta {
        author: "spec_formatting".to_string(),
        reason: Some("sect-pr-in-ppr test".to_string()),
        timestamp_utc: Some("2025-01-01T00:00:00Z".to_string()),
    };
    let _ = runtime.diff_and_redline(&import.doc_handle, &import2.doc_handle, meta);

    // Export and re-import
    let exported = runtime
        .export_docx(&import.doc_handle, ExportMode::Redline)
        .expect("export");

    let verify = SimpleRuntime::new();
    let reimport = verify.import_docx(&exported).expect("re-import");
    let view = verify.view(&reimport.doc_handle).expect("view");
    let doc = view.canonical;

    let paras = common::all_paragraphs(&doc);
    let has_sect_pr = paras.iter().any(|p| p.section_properties.is_some());

    assert!(
        has_sect_pr,
        "sectPr in pPr should survive the redline pipeline (P0 gap if lost). \
         The exported DOCX should preserve section breaks."
    );
}

// ── w:spacing in rPr (character spacing) ────────────────────────────────

/// ISO 29500-1 §17.3.2.35: w:spacing in rPr controls character spacing.
///
/// POSITIVE: char_spacing is now parsed from w:spacing in rPr.
#[test]
fn spec_run_spacing_is_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "run-spacing");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let p = &paras[0];
    let inlines = p.all_inlines_owned();

    let text_nodes: Vec<&stemma::TextNode> = inlines
        .iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect();

    let expanded = text_nodes
        .iter()
        .find(|t| t.text.contains("Expanded"))
        .expect("should have expanded spacing text");

    assert_eq!(
        expanded.style_props.char_spacing,
        Some(60),
        "Expanded spacing run should have char_spacing=60 twips, got {:?}",
        expanded.style_props.char_spacing
    );
}
